import { GoogleGenAI } from "@google/genai";
import { ClientProfile, InsightResponse } from "../types";

const createClient = () => {
    const apiKey = process.env.API_KEY || ''; 
    return new GoogleGenAI({ apiKey });
}

export const generateClientInsight = async (client: ClientProfile): Promise<InsightResponse> => {
  const ai = createClient();

  const prompt = `
    请作为应用分发广告平台（类似华为AppGallery或小米应用商店）的顶级广告分析专家。
    分析以下广告主的全方位数据：

    1. 客户档案: ${client.name} | 行业: ${client.industry} | 级别: ${client.tier}级 | 账户余额可用天数: ${client.financials.walletRunwayDays}
    2. 消耗表现: 今日预算利用率 ${client.budgetUtilization}% | 消耗节奏: ${client.spendVelocity} | 因预算丢失曝光: ${client.lostImpressionsByBudget}%
    3. 转化漏斗: 曝光到付费转化率分布在全链路 ${client.funnel.map(f => f.stage + ':' + f.rate + '%').join(', ')}
    4. 渠道质量: AG平台次留 ${client.channelQualityCompare.find(q => q.metric === '次留')?.ourPlatform}% vs 三方 ${client.channelQualityCompare.find(q => q.metric === '次留')?.thirdParty}%
    5. 风险预警: 7日流失概率 ${client.churnProbability7d}% | CPA偏离度: ${client.cpaAnomaly.deviation}% | 预算瓶颈: ${client.budgetBottleneck}

    任务：
    1. 生成 1 句高管摘要，直指核心痛点或增长机会。
    2. 提供 3 项高价值的行动建议，必须覆盖预算调整、素材优化、人群定向或归因分析。
    3. 提供一个基于目前趋势的未来 14 天战略预测。

    输出格式: JSON 格式，包含 "summary", "actionItems" (数组), "prediction"。内容全部中文。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json'
      }
    });

    return JSON.parse(response.text) as InsightResponse;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    return {
      summary: "由于数据流波动，无法生成精准 AI 洞察。请手动核查 CPA 偏离度。",
      actionItems: ["检查 CPA 同比波动", "审查高频素材疲劳度", "同步财务余额预警"],
      prediction: "近期流量波动较大，建议保持保守出价。"
    };
  }
};

